# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
import secrets
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///reset_tokens.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

class PasswordResetToken(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), nullable=False)
    token = db.Column(db.String(64), unique=True, nullable=False)

db.create_all()

def send_reset_email(email, token):
    reset_link = f"http://example.com/reset-password?token={token}"
    msg = MIMEText(f"Click the link to reset your password: {reset_link}")
    msg['Subject'] = 'Password Reset'
    msg['From'] = 'no-reply@example.com'
    msg['To'] = email

    # Replace with actual SMTP server details
    with smtplib.SMTP('localhost') as server:
        server.send_message(msg)

@app.route('/request-password-reset', methods=['POST'])
def request_password_reset():
    data = request.get_json()
    email = data.get('email')
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    token = secrets.token_urlsafe(32)
    reset_entry = PasswordResetToken(email=email, token=token)
    db.session.add(reset_entry)
    db.session.commit()

    send_reset_email(email, token)

    return jsonify({'message': 'Password reset link sent'}), 200

if __name__ == '__main__':
    app.run(debug=True)